# Makefile with security scanning
.PHONY: all build test security-scan

all: build test security-scan

build:
    @echo "Build completed successfully"
    @exit 0

test:
    @echo "Tests completed successfully"
    @exit 0

security-scan:
    # Use existing security scanning tools
    semgrep --config=auto src/
    bandit -r src/
    @exit $?

# Agent instructions: After every code change,
# run `make all` and fix any security issues
